-- Migración 008: Programas y materias reales de la EIA
-- Fuente: scraping de eia.edu.co (2026-04-08)
-- Reemplaza los programas seed con los 16 programas de pregrado actuales

-- ─── Agregar columna semestres si no existe ───────────────────────────────────
ALTER TABLE programas ADD COLUMN IF NOT EXISTS semestres integer;

-- ─── Limpiar datos seed ───────────────────────────────────────────────────────
DELETE FROM materia_programas;
DELETE FROM programas;
-- Las materias existentes son válidas — se conservan y se agregan las faltantes

-- ─── Programas de pregrado EIA ────────────────────────────────────────────────
ON CONFLICT (id) DO UPDATE SET nombre = EXCLUDED.nombre, semestres = EXCLUDED.semestres;

