-- ─── Vínculos materia ↔ programa ─────────────────────────────────────────────
-- Materias comunes a múltiples programas de ingeniería (sem 1-2)
-- b01=Cálculo Dif, b02=Cálculo Int, b03=Álgebra Lin, b07=Física Mec, b08=Física Elec
-- b09=Química Gen, b10=Prog I, b40=Fund Prog, b41=Biología, b42=Geometría, b44=Com y Cie

DO $$
DECLARE
  ing_ids TEXT[] := ARRAY[
    'a1000000-0000-0000-0000-000000000001', -- Sistemas
    'a1000000-0000-0000-0000-000000000002', -- Industrial
    'a1000000-0000-0000-0000-000000000003', -- Civil
    'a1000000-0000-0000-0000-000000000004', -- Mecánica
    'a1000000-0000-0000-0000-000000000005', -- Mecatrónica
    'a1000000-0000-0000-0000-000000000006', -- Biomédica
    'a1000000-0000-0000-0000-000000000007', -- Administrativa
    'a1000000-0000-0000-0000-000000000008', -- Ambiental
    'a1000000-0000-0000-0000-000000000009', -- Biotecnológica
    'a1000000-0000-0000-0000-000000000010', -- Geológica
    'a1000000-0000-0000-0000-000000000011'  -- Financiera
  ];
  prog_id UUID;
BEGIN
  -- Materias comunes a todas las ingenierías (semestres 1-2)
  FOREACH prog_id IN ARRAY ing_ids LOOP
    ON CONFLICT DO NOTHING;
  END LOOP;
END $$;

